; EarthBound C1 Bank-end text metric callback and checksum tail.
;
; Source-emission status:
; - Prototype level: build-candidate
; - Generated by tools/emit_linear_source_module.py from a state-aware
;   linear ROM decode, then intended for byte-equivalence validation.
;
; Source units covered:
; - C1:FF99..C1:FFD3 ComputeCenteredTextLayoutMetric
; - C1:FFD3..C1:FFEF ComputeBankC1ChecksumTail
; - C1:FFEF..C1:10000 BankC1ChecksumConstantAndPadding
;
; Runtime contract:
; - `C1:FF99` is a C4 text-layout callback. It measures the current text/control
;   value through `C4:3E31`, centers it against incoming X multiplied by 8, and
;   stores fine/coarse offsets in `$9E23/$9E25`.
; - `C1:FFD3` computes the bank-C1 checksum tail value into `$B539`; the final
;   bytes are checksum constant plus bank-end padding, not executable logic.

; ---------------------------------------------------------------------------
; External contracts used by this module

C0A11C_BankC0ChecksumSourceTable = $C0A11C
C1FFEF_BankC1ChecksumConstant    = $C1FFEF
C43E31_MeasureTextControlValue   = $C43E31

; ---------------------------------------------------------------------------
; C1:FF99

C1FF99_ComputeCenteredTextLayoutMetric:
    rep #$31
    phd
    pha
    tdc
    adc.w #$FFEC
    tcd
    pla
    txy
    sty $12
    tax
    lda $22
    sta $06
    lda $24
    sta $08
    lda $06
    sta $0E
    lda $08
    sta $10
    txa
    jsl C43E31_MeasureTextControlValue
    sta $02
    ldy $12
    tya
    asl A
    asl A
    asl A
    sec
    sbc $02
    lsr A
    sta $9E23
    lsr A
    lsr A
    lsr A
    sta $9E25
    pld
    rtl
SRAM_CHECK_ROUTINE_CHECKSUM:
C1FFD3_ComputeBankC1ChecksumTail = SRAM_CHECK_ROUTINE_CHECKSUM
    ldx.w #$0033
    rep #$20
    lda.w #$0000
    sta $B539
C1FFDE_ComputeBankC1ChecksumTail_LFFDE:
    clc
    adc C0A11C_BankC0ChecksumSourceTable,X
    dex
    bpl C1FFDE_ComputeBankC1ChecksumTail_LFFDE
    sec
    sbc C1FFEF_BankC1ChecksumConstant
    sta $B539
    rtl

; ---------------------------------------------------------------------------
; C1:FFEF

SRAM_CHECK_ROUTINE_CHECKSUM_VALUE:
C1FFEF_BankC1ChecksumConstantAndPadding = SRAM_CHECK_ROUTINE_CHECKSUM_VALUE
    ; checksum constant followed by bank-end padding
    db $D8,$2A,$00,$00,$00,$00,$00,$00,$00,$00,$00,$00,$00,$00,$00,$00
    db $00

; C1:10000
